import React from 'react';
import { Card, CardContent, Box, Typography, Stack, CircularProgress } from '@mui/material';
import response from './response.json';

interface EventCountdownData {
  event: {
    name: string;
    date: string;
  };
  countdown: {
    daysRemaining: number;
    progressPercentage: number;
  };
}

export default function Widget() {
  const eventData = response.data as EventCountdownData;
  const { event, countdown } = eventData;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 280,
        maxWidth: 380,
        bgcolor: '#303030',
        color: '#FFFFFF',
        borderRadius: 2,
        boxShadow: 3,
      }}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2} alignItems="center">
          <Box>
            <Typography variant="h6" fontWeight={600}>
              {event.name}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ color: '#BBBBBB' }}>
              {event.date}
            </Typography>
          </Box>

          <Box position="relative" display="inline-flex">
            <CircularProgress
              variant="determinate"
              value={countdown.progressPercentage}
              size={100}
              thickness={4}
              sx={{
                color: '#FF5722',
              }}
            />
            <Box
              top={0}
              left={0}
              bottom={0}
              right={0}
              position="absolute"
              display="flex"
              alignItems="center"
              justifyContent="center"
            >
              <Typography variant="h5" fontWeight={700}>
                {countdown.daysRemaining}
              </Typography>
            </Box>
          </Box>

          <Typography variant="body2" sx={{ color: '#FFC107' }}>
            days remaining
          </Typography>
        </Stack>
      </CardContent>
    </Card>
  );
}
